%[text] # 例7.5（線形再量子化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example07_05"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1)
subplot(1,3,1) %[output:0f254348]
imshow(X) %[output:0f254348]
title('原画像') %[output:0f254348]
%imwrite(X,fullfile(resfolder,myfilename+"org"),imgfmt)

% GPUに転送
%X = gpuArray(X);
%%
%[text] ## 6bppへの再量子化
alpha = 6;
Q = 1/(2^alpha-1);
Y6 = Q*round(X/Q);
subplot(1,3,2) %[output:0c7576d4]
imshow(Y6) %[output:0c7576d4]
title(num2str(alpha)+" bpp PSNR: " + num2str(psnr(X,Y6)) + " dB") %[output:0c7576d4]
imwrite(Y6,fullfile(resfolder,"fig07-09a.png"))
%%
%[text] ## 4bppへの再量子化
gamma = 4;
Q = 1/(2^gamma-1);
Y4 = Q*round(X/Q);
subplot(1,3,3) %[output:9c2e80ce]
imshow(Y4) %[output:9c2e80ce]
title(num2str(gamma)+" bpp PSNR: " + num2str(psnr(X,Y4)) + " dB") %[output:9c2e80ce]
imwrite(Y4,fullfile(resfolder,"fig07-09b.png"))

